import React from 'react';
import ReactDOM from 'react-dom/client'; // note o '/client'

// abaixo estamos criando um componente personalizado. A primeira letra do nome deve ser maiúscula. O nome do arquivo pode ser minúsculo.
import Primeiro from './componentes/Primeiro';

// abaixo, é feita a renderização do conteudo do componente que foi definido no arquivo "componentes/primeiro"
ReactDOM.createRoot(document.getElementById('root')).render(<Primeiro/>);

// a linha comentada abaixo vai fazer com que seja inserido o conteúdo no browser com o componente não personalizado que é o <h1>React</h1>, porque o conteúdo dentro da tag não é referente a um import de um arquivo que recebeu um nome. 
